// Define a function to fix the CSS variable priority.
function fixCssPriority(cssString) {
  // Split the input CSS string into blocks.
  const blocks = cssString.split('}');
  // Initialize an object to store the variable definitions.
  const variables = {};
  // Iterate over the blocks.
  for (let block of blocks) {
    // Extract the variable definition from the block.
    const variable = block.split('{')[0].trim();
    // Add the variable to the object.
    variables[variable] = block;
    // Find all occurrences of the variable in the remaining blocks.
    for (let otherBlock of blocks.slice(blocks.indexOf(block) + 1)) {
      // Replace the variable with the correct value.
      otherBlock = otherBlock.replace(variable, block);
    }
  }
  // Join the blocks back together.
  return blocks.join('}');
}

// Call the function with the input CSS string.
const cssInput = ':root { --primary-color: #333; } .container { background-color: var(--primary-color); } .container .header { background-color: #666; }';
